}

sp_widget.description:
2.7 Added Angular Provider htmlToStringService;
Server script updated to use TaskWidgetData instead of TemplateWidgetData;
Client controller, deleted _convertHtmlToSimpleString() which was added on 2021-06-25;

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES & BRIAN KEENER
// GRAPHICAL TREE FOR PROCESS DEFINITION
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//                                          Changes in Client controller
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//											 Instruction or Signature Instructions need to convert HTML to string;
//											 Combine Template Widget Data into Task Widget Data
//                                          Changes in Server script and Client controller
// 2.7.0 | 2021-07-21 | raj | STRY0101803 - Allow for a page just for Scheduled Tasks
//                                          Changes in Server script, HTML


//------------------------------------------------------------------------------------------------------------------------

(function() {
    // STRY0091260
    data.durationTitle = gs.getMessage('Tasker - Title - Duration Modal');
    data.assignmentTitle = gs.getMessage('Tasker - Title - Assignment Modal');
    data.operationalTitle = gs.getMessage('Tasker - Title - Operational Modal');
    data.durationWarningParentLessThanCombinedSubtasks = gs.getMessage('Tasker - Warning: Parent duration shorter than the durations of subtasks');
    data.durationWarningIsSubTaskLongerThanParent = gs.getMessage('Tasker - Warning: Parent Duration is Shorter than a subtasks');
    data.durationWarningisParentShorterThanThisTask = gs.getMessage('Tasker - Warning: Subtask Duration is longer than parent');

    data.durationWarningWaitState = gs.getMessage('Tasker - Warning: Wait state set with no subtasks');
    data.durationWarning = gs.getMessage('Tasker -  Warning Duration');
    data.assignmentWarning = gs.getMessage('Tasker -  Warning Assignment');

    //data.placeholderMsg = gs.getMessage("Select Template ...");
    var map = data.map = [];
    data.pageTemplateDetails = "discovertasker_processtemplatedetails"; //"discovertasker_processtemplatedetails";
    data.table_detail = "x_153465_discovert_route_tasks";
    //------------------------------------------------------------------------------------------------------------------------
    // CUSTOM
    //------------------------------------------------------------------------------------------------------------------------
    data.page_id = $sp.getParameter("id");
    data.view = $sp.getParameter("view");
    data.filter = $sp.getParameter("filter");
    data.table = $sp.getParameter("table");
    data.isValid = true;
    data.sys_id = $sp.getParameter("sys_id");
    data.templateId = "return none until set";
    //----------------------------------------------------------------------------------------------------
    // Initializing Variables
    //----------------------------------------------------------------------------------------------------
    var sys_id = data.sys_id;
    var id = "";

    if (input) {
        data.table = input.table;
        data.sys_id = input.sys_id;
        //id =  input.sys_id;
        sys_id = input.sys_id;
    }

    // STRY0072032
    data.isSystemTreeOrientationVertical = new tasking_System_Settings_Scripts().systemControlSetting().VerticalTree;

    //------------------------------------------------------------------------------------------------------------------------
    // GET THE TOP PARENT FOR THE CURRENT SYS_ID
    //------------------------------------------------------------------------------------------------------------------------
    var currentRecord = new GlideRecordSecure(data.table);
    if (currentRecord.get(sys_id)) {
			// STRY0101803 - Allow for a page just for Scheduled Tasks
			var grTemplate;
			switch (data.table) {
				case 'x_153465_discovert_route_tasks':
					// Make sure you have top task def by getting the Template and setting the ID to the parent_task_def
					grTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
					if (grTemplate.get(currentRecord.tasker_process_definition)) {
						id = grTemplate.getValue('parent_task_def');
					}
					break;
				case 'x_153465_discovert_discover_routing_template':
					id = currentRecord.getValue('parent_task_def');
					break;
				case 'x_153465_discovert_tasker_schedule':
					// Make sure you have top task def by getting the Template and setting the ID to the parent_task_def
					grTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
					if (grTemplate.get(currentRecord.tasker_process)) {
						id = grTemplate.getValue('parent_task_def');
					}
			}
    }
    //------------------------------------------------------------------------------------------------------------------------

    if (!id) {
        data.id = null;
        return;
    }
    var gr = new GlideRecordSecure('x_153465_discovert_route_tasks');
    if (gr.get(id)) {
        var uiChec = new uiConditionCheck();
        data.canRunTemplate = uiChec.runTemplateUIAction(gr);
        data.id = id;
        data.title = gr.getValue('short_description');
        // RJ - TUP - STRY0068618 - added run template
        data.topParentTask_id = id;
        data.templateId = gr.getValue('tasker_process_definition');
        data.templateName = gr.getDisplayValue('tasker_process_definition');
        // STRY0040294 - use record watcher to keep grid synced
        // STRY0091251
        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering
        // var templateWidgetData = new TemplateWidgetData();
        // data.fieldsInModel = templateWidgetData.loadTemplateTreeFieldsInModelAndFieldLabels(gr);
        // templateWidgetData.buildTemplateMap('discovertasker-processtemplatetreegraph', map, gr, data.fieldsInModel)
        var taskWidgetData = new TaskWidgetData();
        data.fieldsInModel = taskWidgetData.loadTemplateTreeFieldsInModelAndFieldLabels(gr);
        taskWidgetData.buildTaskMap('discovertasker-processtemplatetreegraph', map, gr, data.fieldsInModel);
    }

})();
